INSERT INTO public.aml_program_question_templates
  (submodule, control_area, control_category, question_number, question_text, regulatory_reference, evidence_required, sort_order, regulatory_category, test_procedure, analyst_guidance, pass_criteria, max_points, section_code, section_name, subsection, question_code, is_new_or_updated)
VALUES
('policies_procedures','core_controls','document_control_governance',1,'Policy title','PCMLTFR',true,1,'Requirement',NULL,'Confirm the policy/procedure manual has a formal title and clearly identifies the document owner.','Document title and owner are clearly shown.',NULL,'1','Document Control & Governance','Document Control','DCG-01',false),
('policies_procedures','core_controls','document_control_governance',2,'Version control','PCMLTFR',true,2,'Requirement',NULL,'Confirm the document carries version number, issue date, effective date and next/review date.','Versioning and dates are visible and internally consistent.',NULL,'1','Document Control & Governance','Document Control','DCG-02',false),
('policies_procedures','core_controls','document_control_governance',3,'Approval evidence','PCMLTFR',true,3,'Requirement',NULL,'Confirm the policy is approved by the appropriate authority (Board / directors / senior management) and dated.','Approval authority, approver name/role and date are documented.',NULL,'1','Document Control & Governance','Approval','DCG-03',false),
('policies_procedures','core_controls','document_control_governance',4,'Amendment history','PCMLTFR',true,4,'Requirement',NULL,'Confirm a change log or revision history exists and reflects recent amendments.','Change history identifies what changed, when, and by whom.',NULL,'1','Document Control & Governance','Change log','DCG-04',false),
('policies_procedures','core_controls','document_control_governance',5,'Core AML/ATF laws','PCMLTFA / PCMLTFR',true,5,'Requirement',NULL,'Confirm the policy references the PCMLTFA and its Regulations, and aligns internal obligations to those legal instruments.','PCMLTFA and PCMLTFR are expressly cited and used as governing references.',NULL,'1','Document Control & Governance','Legislative references','DCG-05',false),
('policies_procedures','core_controls','document_control_governance',6,'Sanctions / related laws','UN Act / SEMA / JVCFOA / Criminal Code',true,6,'Requirement',NULL,'Confirm the policy references sanctions-related legislation relevant to the business (e.g., SEMA, United Nations Act, Justice for Victims of Corrupt Foreign Officials Act, Criminal Code / RIUNRST where relevant).','Relevant sanctions / terrorist property statutes are referenced or cross-referenced.',NULL,'1','Document Control & Governance','Legislative references','DCG-06',false),
('policies_procedures','core_controls','document_control_governance',7,'FINTRAC guidance','FINTRAC Guidance',true,7,'Requirement',NULL,'Confirm the policy references FINTRAC guidance and internal procedures where operational interpretation is required.','Policy cross-references current FINTRAC guidance and/or internal playbooks.',NULL,'1','Document Control & Governance','Guidance references','DCG-07',false);
INSERT INTO public.aml_program_question_templates
  (submodule, control_area, control_category, question_number, question_text, regulatory_reference, evidence_required, sort_order, regulatory_category, test_procedure, analyst_guidance, pass_criteria, max_points, section_code, section_name, subsection, question_code, is_new_or_updated)
VALUES
('policies_procedures','core_controls','effective_compliance_regime',8,'Complete compliance regime','PCMLTFR s.71',true,8,'Requirement',NULL,'Confirm the policy states that the firm maintains an effective compliance regime/program.','Policy expressly refers to an effective compliance regime/program.',NULL,'2','Effective Compliance Regime','Five pillars','ECR-01',false),
('policies_procedures','core_controls','effective_compliance_regime',9,'Compliance officer pillar','PCMLTFR s.71',true,9,'Requirement',NULL,'Confirm the compliance officer pillar is addressed.','The role is expressly included as a required program element.',NULL,'2','Effective Compliance Regime','Five pillars','ECR-02',false),
('policies_procedures','core_controls','effective_compliance_regime',10,'Policies and procedures pillar','PCMLTFR s.71',true,10,'Requirement',NULL,'Confirm written policies and procedures are identified as a required element.','Written policies/procedures are expressly included and linked to operations.',NULL,'2','Effective Compliance Regime','Five pillars','ECR-03',false),
('policies_procedures','core_controls','effective_compliance_regime',11,'Risk assessment pillar','PCMLTFR s.71',true,11,'Requirement',NULL,'Confirm a documented risk assessment is identified as a required element.','Risk assessment is expressly included and tied to controls/monitoring.',NULL,'2','Effective Compliance Regime','Five pillars','ECR-04',false),
('policies_procedures','core_controls','effective_compliance_regime',12,'Training pillar','PCMLTFR s.71',true,12,'Requirement',NULL,'Confirm training is identified as a required element.','Training program is expressly included and described at a high level.',NULL,'2','Effective Compliance Regime','Five pillars','ECR-05',false),
('policies_procedures','core_controls','effective_compliance_regime',13,'Effectiveness review pillar','PCMLTFR s.71',true,13,'Requirement',NULL,'Confirm effectiveness review/testing is identified as a required element.','Effectiveness review is expressly included with a defined cadence.',NULL,'2','Effective Compliance Regime','Five pillars','ECR-06',false);
INSERT INTO public.aml_program_question_templates
  (submodule, control_area, control_category, question_number, question_text, regulatory_reference, evidence_required, sort_order, regulatory_category, test_procedure, analyst_guidance, pass_criteria, max_points, section_code, section_name, subsection, question_code, is_new_or_updated)
VALUES
('policies_procedures','core_controls','roles_responsibilities',14,'Directors / Board oversight','PCMLTFR',true,14,'Requirement',NULL,'Confirm directors / Board (or equivalent) responsibilities are defined.','Oversight, approval, challenge and remediation oversight responsibilities are documented.',NULL,'3','Roles & Responsibilities','Governance','RR-01',false),
('policies_procedures','core_controls','roles_responsibilities',15,'Owners','PCMLTFR',true,15,'Requirement',NULL,'Confirm owners'' responsibilities are defined where applicable.','Owners'' accountability for providing truthful ownership information and supporting compliance is documented.',NULL,'3','Roles & Responsibilities','Governance','RR-02',false),
('policies_procedures','core_controls','roles_responsibilities',16,'Senior management','PCMLTFR',true,16,'Requirement',NULL,'Confirm senior management responsibilities are defined.','Senior management is responsible for resourcing, supporting and acting on escalation/reporting.',NULL,'3','Roles & Responsibilities','Management','RR-03',false),
('policies_procedures','core_controls','roles_responsibilities',17,'Compliance officer','PCMLTFR s.71',true,17,'Requirement',NULL,'Confirm the compliance officer role, authority, independence and reporting line are defined.','Role includes authority, independence, access to records/resources and escalation rights.',NULL,'3','Roles & Responsibilities','Compliance','RR-04',false),
('policies_procedures','core_controls','roles_responsibilities',18,'Segregation of Duties','FINTRAC Guidance',true,18,'Best Practice',NULL,'Confirm that the appointed compliance officer of a larger corporation is not directly involved in the receipt, transfer or payment of funds.','As a best practice, the appointed compliance officer of a larger business should not be directly involved in the receipt, transfer or payment of funds.',NULL,'3','Roles & Responsibilities','Compliance','RR-05',false),
('policies_procedures','core_controls','roles_responsibilities',19,'Employees / front line','PCMLTFR',true,19,'Requirement',NULL,'Confirm employee responsibilities are defined.','Employees must follow procedures, complete training, identify/escalate unusual activity and maintain confidentiality.',NULL,'3','Roles & Responsibilities','Operations','RR-06',false),
('policies_procedures','core_controls','roles_responsibilities',20,'Internal reporting','PCMLTFR',true,20,'Requirement',NULL,'Confirm escalation pathways are defined.','Operational staff know when and to whom to escalate KYC, BO, PEP, reporting and sanctions issues.',NULL,'3','Roles & Responsibilities','Escalation','RR-07',false);
INSERT INTO public.aml_program_question_templates
  (submodule, control_area, control_category, question_number, question_text, regulatory_reference, evidence_required, sort_order, regulatory_category, test_procedure, analyst_guidance, pass_criteria, max_points, section_code, section_name, subsection, question_code, is_new_or_updated)
VALUES
('policies_procedures','core_controls','msb_registration_filings',21,'Initial registration timing','PCMLTFR',true,21,'Requirement',NULL,'Confirm the policy states MSB/FMSB registration must occur before business commences.','Policy clearly says no MSB activity may start before registration is in place.',NULL,'4','MSB Registration & FINTRAC Notifications','Registration','MSB-01',false),
('policies_procedures','core_controls','msb_registration_filings',22,'Renewal timing','PCMLTFR',true,22,'Requirement',NULL,'Confirm the policy states renewal must occur before expiry and recognizes the 2-year registration validity period.','Renewal timing and validity period are clearly stated.',NULL,'4','MSB Registration & FINTRAC Notifications','Registration','MSB-02',false),
('policies_procedures','core_controls','msb_registration_filings',23,'30-day update rule','PCMLTFR s.11.13',true,23,'Requirement',NULL,'Confirm the policy requires updates to FINTRAC within 30 days of a change.','30-day update rule is stated for ownership, address, activities/services and other material changes.',NULL,'4','MSB Registration & FINTRAC Notifications','Registration','MSB-03',false),
('policies_procedures','core_controls','msb_registration_filings',24,'Cessation notice','PCMLTFR',true,24,'Requirement',NULL,'Confirm the policy requires cessation/termination notice within 30 days after the business ceases.','Policy clearly states FINTRAC must be notified within 30 days of cessation.',NULL,'4','MSB Registration & FINTRAC Notifications','Registration','MSB-04',false),
('policies_procedures','core_controls','msb_registration_filings',25,'Recordkeeping for registration lifecycle','PCMLTFR',true,25,'Requirement',NULL,'Confirm procedures retain evidence of registration, renewals, updates and cessation filings.','Acknowledgements/submissions are retained and accessible.',NULL,'4','MSB Registration & FINTRAC Notifications','Registration','MSB-05',false),
('policies_procedures','core_controls','msb_registration_filings',26,'Inquiry from FINTRAC','PCMLTFR',true,26,'Requirement',NULL,'Confirm the policy requires response to FINTRAC within 30 days of such inquiry.','Policy clearly states FINTRAC''s inquiry must be responded to within 30 days of such inquiry.',NULL,'4','MSB Registration & FINTRAC Notifications','Registration','MSB-06',false);
INSERT INTO public.aml_program_question_templates
  (submodule, control_area, control_category, question_number, question_text, regulatory_reference, evidence_required, sort_order, regulatory_category, test_procedure, analyst_guidance, pass_criteria, max_points, section_code, section_name, subsection, question_code, is_new_or_updated)
VALUES
('policies_procedures','core_controls','client_identification_kyc',27,'Trigger events','PCMLTFR',true,27,'Requirement',NULL,'Confirm the policy lists all identity-verification trigger events relevant to the business model.','Trigger events are specific, complete and testable.',NULL,'5','Client Identification & KYC','Triggers','KYC-01',false),
('policies_procedures','core_controls','client_identification_kyc',28,'Exemptions','PCMLTFR',true,28,'Requirement',NULL,'Confirm any statutory/sector exemptions are documented and differentiated from general trigger rules.','Exemptions are documented with conditions and do not contradict trigger requirements.',NULL,'5','Client Identification & KYC','Triggers','KYC-02',false),
('policies_procedures','core_controls','client_identification_kyc',29,'Government photo ID','PCMLTFR',true,29,'Requirement',NULL,'Confirm the government-issued photo ID method is described.','Policy states ID must be authentic, valid and current; method is usable in practice.',NULL,'5','Client Identification & KYC','Individuals','KYC-03',false),
('policies_procedures','core_controls','client_identification_kyc',30,'Non-face-to-face photo ID','PCMLTFR; FINTRAC Guidance',true,30,'Requirement',NULL,'Confirm non-face-to-face photo ID controls are described.','Policy requires technology/processes to assess authenticity and link the presenter to the ID.',NULL,'5','Client Identification & KYC','Individuals','KYC-04',false),
('policies_procedures','core_controls','client_identification_kyc',31,'Credit file method','PCMLTFR',true,31,'Requirement',NULL,'Confirm the credit file method criteria are described.','Policy states the file must satisfy the minimum age/currentness/tradeline and matching requirements, and be obtained at time of verification.',NULL,'5','Client Identification & KYC','Individuals','KYC-05',false),
('policies_procedures','core_controls','client_identification_kyc',32,'Dual-process method','PCMLTFR',true,32,'Requirement',NULL,'Confirm dual-process criteria are described.','Policy requires two different reliable sources and permitted information combinations.',NULL,'5','Client Identification & KYC','Individuals','KYC-06',false),
('policies_procedures','core_controls','client_identification_kyc',33,'Reliance / affiliate / member methods','PCMLTFR',true,33,'Requirement',NULL,'Confirm permitted reliance / affiliate / member methods are described if used.','Policy states when reliance is allowed, what prior method must have been used, and what matching/recordkeeping is required.',NULL,'5','Client Identification & KYC','Individuals','KYC-07',false),
('policies_procedures','core_controls','client_identification_kyc',34,'Children / persons lacking standard ID','PCMLTFR',true,34,'Requirement',NULL,'Confirm special-case procedures exist where relevant.','Policy provides a compliant path for minors or customers lacking standard verification documents where the business offers such products.',NULL,'5','Client Identification & KYC','Special situations','KYC-08',false),
('policies_procedures','core_controls','client_identification_kyc',35,'Entity verification','PCMLTFR',true,35,'Requirement',NULL,'Confirm entity verification procedures are described by entity type.','Acceptable records and required fields are defined for corporations/trusts/other entities as applicable.',NULL,'5','Client Identification & KYC','Entities','KYC-09',false),
('policies_procedures','core_controls','client_identification_kyc',36,'ID recordkeeping','PCMLTFR',true,36,'Requirement',NULL,'Confirm identity-verification recordkeeping requirements are described by method.','Policy states what must be kept for each method and for how long.',NULL,'5','Client Identification & KYC','Recordkeeping','KYC-10',false),
('policies_procedures','core_controls','client_identification_kyc',37,'Updating KYC','PCMLTFR',true,37,'Requirement',NULL,'Confirm there is a procedure for updating customer''s records.','Policy requires KYC information to be refreshed on a risk-based cadence or on material-change events.',NULL,'5','Client Identification & KYC','KYC Refresh','KYC-11',false);
INSERT INTO public.aml_program_question_templates
  (submodule, control_area, control_category, question_number, question_text, regulatory_reference, evidence_required, sort_order, regulatory_category, test_procedure, analyst_guidance, pass_criteria, max_points, section_code, section_name, subsection, question_code, is_new_or_updated)
VALUES
('policies_procedures','core_controls','business_relationships_monitoring',38,'When relationship is established','PCMLTFR',true,38,'Requirement',NULL,'Confirm the policy defines when a business relationship begins for the sector.','Start-of-relationship triggers are clear and aligned to sector rules.',NULL,'6','Business Relationship & Ongoing Monitoring','Lifecycle','BR-01',false),
('policies_procedures','core_controls','business_relationships_monitoring',39,'Purpose / intended nature','PCMLTFR',true,39,'Requirement',NULL,'Confirm the policy requires recording the purpose and intended nature of the business relationship.','Required record is clearly described and operationalized.',NULL,'6','Business Relationship & Ongoing Monitoring','Lifecycle','BR-02',false),
('policies_procedures','core_controls','business_relationships_monitoring',40,'When relationship ends','PCMLTFR',true,40,'Requirement',NULL,'Confirm the policy defines when a business relationship ends.','End-of-relationship logic is documented and usable by analysts.',NULL,'6','Business Relationship & Ongoing Monitoring','Lifecycle','BR-03',false),
('policies_procedures','core_controls','business_relationships_monitoring',41,'Ongoing monitoring framework','PCMLTFR',true,41,'Requirement',NULL,'Confirm the policy requires ongoing monitoring of business relationships.','Monitoring is risk-based and linked to the relationship record.',NULL,'6','Business Relationship & Ongoing Monitoring','Monitoring','BR-04',false),
('policies_procedures','core_controls','business_relationships_monitoring',42,'Enhanced due diligence','PCMLTFR',true,42,'Requirement',NULL,'Confirm higher-risk relationships receive enhanced measures.','Frequency/intensity of review increases with risk and is described in plain language.',NULL,'6','Business Relationship & Ongoing Monitoring','Monitoring','BR-05',false),
('policies_procedures','core_controls','business_relationships_monitoring',43,'Escalation of unusual activity','PCMLTFR',true,43,'Requirement',NULL,'Confirm unusual activity/investigation escalation is described.','The policy explains when monitoring output becomes investigation and/or STR consideration.',NULL,'6','Business Relationship & Ongoing Monitoring','Monitoring','BR-06',false),
('policies_procedures','core_controls','business_relationships_monitoring',44,'Derisking / demarketing','FINTRAC Guidance',true,44,'Best Practice',NULL,'Confirm the policy addresses derisking/demarketing procedures and (for larger institutions) ongoing monitoring of accounts already recommended for demarketing.','Policy defines criteria, governance, approvals, fair-treatment, recordkeeping; and ongoing monitoring of demarketing-flagged accounts where applicable.',NULL,'6','Business Relationship & Ongoing Monitoring','Monitoring','BR-07',true);
INSERT INTO public.aml_program_question_templates
  (submodule, control_area, control_category, question_number, question_text, regulatory_reference, evidence_required, sort_order, regulatory_category, test_procedure, analyst_guidance, pass_criteria, max_points, section_code, section_name, subsection, question_code, is_new_or_updated)
VALUES
('policies_procedures','core_controls','third_party_determination',45,'What a third party is','PCMLTFR',true,45,'Requirement',NULL,'Confirm the policy defines who a third party is.','The policy defines third party clearly.',NULL,'7','Third Party Determination','Definitions','TPD-01',false),
('policies_procedures','core_controls','third_party_determination',46,'Large cash transactions','PCMLTFR',true,46,'Requirement',NULL,'Confirm the policy requires third party determination when a large cash transaction trigger applies.','Large cash trigger is explicitly listed.',NULL,'7','Third Party Determination','Triggers','TPD-02',false),
('policies_procedures','core_controls','third_party_determination',47,'Large virtual currency transactions','PCMLTFR',true,47,'Requirement',NULL,'Confirm the policy requires third party determination when a large VC transaction trigger applies.','Large VC trigger is explicitly listed.',NULL,'7','Third Party Determination','Triggers','TPD-03',false),
('policies_procedures','core_controls','third_party_determination',48,'Information record / account opening scenarios','PCMLTFR',true,48,'Requirement',NULL,'Confirm the policy covers the applicable information-record / account-opening / signature-card third-party triggers for the sector.','Relevant sector triggers are explicitly listed.',NULL,'7','Third Party Determination','Triggers','TPD-04',false),
('policies_procedures','core_controls','third_party_determination',49,'How determination is made','PCMLTFR',true,49,'Requirement',NULL,'Confirm the policy explains how staff determine whether a third party exists.','Staff are instructed to ask the client, document the answer and escalate concerns.',NULL,'7','Third Party Determination','Process','TPD-05',false),
('policies_procedures','core_controls','third_party_determination',50,'Required fields','PCMLTFR',true,50,'Requirement',NULL,'Confirm the required third-party details are listed.','Required identifying details and relationship-to-client fields are spelled out.',NULL,'7','Third Party Determination','Recordkeeping','TPD-06',false),
('policies_procedures','core_controls','third_party_determination',51,'Unable to determine but suspected','PCMLTFR',true,51,'Requirement',NULL,'Confirm the policy addresses cases where a third party is suspected but cannot be confirmed.','Policy requires documenting suspicion and escalating appropriately.',NULL,'7','Third Party Determination','Escalation','TPD-07',false);
INSERT INTO public.aml_program_question_templates
  (submodule, control_area, control_category, question_number, question_text, regulatory_reference, evidence_required, sort_order, regulatory_category, test_procedure, analyst_guidance, pass_criteria, max_points, section_code, section_name, subsection, question_code, is_new_or_updated)
VALUES
('policies_procedures','core_controls','beneficial_ownership_discrepancy',52,'25%+ ownership/control','PCMLTFR',true,52,'Requirement',NULL,'Confirm the policy requires identifying individuals who directly or indirectly own/control 25% or more, as applicable.','25% threshold and indirect ownership/control concepts are stated.',NULL,'8','Beneficial Ownership & Discrepancy Reporting','Baseline','BO-01',false),
('policies_procedures','core_controls','beneficial_ownership_discrepancy',53,'BO Cannot be another corporation','PCMLTFR',true,53,'Requirement',NULL,'Confirm that the policy states that BO cannot be other corporations, trusts or other entities. They must be the individuals who are the owners or controllers of the entity.','BO must be a natural person, not another entity.',NULL,'8','Beneficial Ownership & Discrepancy Reporting','Baseline','BO-02',false),
('policies_procedures','core_controls','beneficial_ownership_discrepancy',54,'Ownership / control / structure','PCMLTFR',true,54,'Requirement',NULL,'Confirm the policy requires obtaining information that establishes ownership, control and structure.','Analysts can see exactly what structure information should be collected.',NULL,'8','Beneficial Ownership & Discrepancy Reporting','Baseline','BO-03',false),
('policies_procedures','core_controls','beneficial_ownership_discrepancy',55,'Corporation/trust/other-entity specifics','PCMLTFR',true,55,'Requirement',NULL,'Confirm the policy differentiates the data required for corporations, trusts and other entities.','Entity-type-specific fields are identified where applicable.',NULL,'8','Beneficial Ownership & Discrepancy Reporting','Baseline','BO-04',false),
('policies_procedures','core_controls','beneficial_ownership_discrepancy',56,'Unable to confirm beneficial ownership','PCMLTFR',true,56,'Requirement',NULL,'Confirm the policy states what to do if beneficial ownership cannot be confirmed.','Reasonable measures, escalation, high-risk treatment and enhanced monitoring are required.',NULL,'8','Beneficial Ownership & Discrepancy Reporting','Escalation','BO-05',false),
('policies_procedures','core_controls','beneficial_ownership_discrepancy',57,'No beneficial owner exists','PCMLTFR',true,57,'Requirement',NULL,'Confirm the policy states what to do where no beneficial owner exists.','Policy requires documenting rationale, structure reviewed and evidence supporting the conclusion.',NULL,'8','Beneficial Ownership & Discrepancy Reporting','Edge case','BO-06',false),
('policies_procedures','core_controls','beneficial_ownership_discrepancy',58,'Material BO discrepancy definition','Corporations Canada (Oct 1, 2025)',true,58,'Requirement',NULL,'Confirm the policy defines a reportable / material beneficial ownership discrepancy where relevant.','Definition is clear enough for analysts to recognize the issue.',NULL,'8','Beneficial Ownership & Discrepancy Reporting','Discrepancy','BO-07',true),
('policies_procedures','core_controls','beneficial_ownership_discrepancy',59,'Resolution process','Corporations Canada (Oct 1, 2025)',true,59,'Requirement',NULL,'Confirm the policy requires attempts to resolve a BO discrepancy before reporting it externally.','Resolution attempts, timing and ownership are documented.',NULL,'8','Beneficial Ownership & Discrepancy Reporting','Discrepancy','BO-08',true),
('policies_procedures','core_controls','beneficial_ownership_discrepancy',60,'Reporting to Corporations Canada','Corporations Canada (Oct 1, 2025)',true,60,'Requirement',NULL,'Confirm the policy describes when and how to report an unresolved/material discrepancy to Corporations Canada.','Submission path, timing and evidence retention are described.',NULL,'8','Beneficial Ownership & Discrepancy Reporting','Discrepancy','BO-09',true),
('policies_procedures','core_controls','beneficial_ownership_discrepancy',61,'FINTRAC escalation / suspicious activity link','PCMLTFR',true,61,'Requirement',NULL,'Confirm the policy routes suspicious BO discrepancies into suspicious transaction/escalation logic.','Suspicious BO issues are linked to STR/investigation escalation where appropriate.',NULL,'8','Beneficial Ownership & Discrepancy Reporting','Discrepancy','BO-10',false),
('policies_procedures','core_controls','beneficial_ownership_discrepancy',62,'BO records','PCMLTFR',true,62,'Requirement',NULL,'Confirm BO recordkeeping requirements are described.','BO records, measures taken and reporting acknowledgements are retained.',NULL,'8','Beneficial Ownership & Discrepancy Reporting','Recordkeeping','BO-11',false);
