INSERT INTO public.aml_program_question_templates
  (submodule, control_area, control_category, question_number, question_text, regulatory_reference, evidence_required, sort_order, regulatory_category, test_procedure, analyst_guidance, pass_criteria, max_points, section_code, section_name, subsection, question_code, is_new_or_updated)
VALUES
('policies_procedures','core_controls','reporting_obligations',73,'Large cash reporting','PCMLTFR',true,73,'Requirement',NULL,'Confirm LCTR obligations, threshold, aggregation rule and timeline are described. Static with defined timeframe and time zone.','$10K threshold, 24-hour aggregation concept and 15-calendar-day reporting timeline are stated.',NULL,'10','Reporting Obligations','LCTR','REP-01',false),
('policies_procedures','core_controls','reporting_obligations',74,'Electronic funds transfer reporting','PCMLTFR',true,74,'Requirement',NULL,'Confirm EFTR obligations, threshold and timeline are described. Static with defined timeframe and time zone.','Threshold and 5-business-day reporting timeline are stated in operational terms.',NULL,'10','Reporting Obligations','EFTR','REP-02',false),
('policies_procedures','core_controls','reporting_obligations',75,'Large virtual currency transaction reporting','PCMLTFR',true,75,'Requirement',NULL,'Confirm LVCTR obligations, threshold, aggregation rule and timeline are described. Static with defined timeframe and time zone.','$10K threshold, 24-hour aggregation concept and 5-working-day reporting timeline are stated.',NULL,'10','Reporting Obligations','LVCTR','REP-03',false),
('policies_procedures','core_controls','reporting_obligations',76,'Suspicious transaction reporting','PCMLTFR',true,76,'Requirement',NULL,'Confirm suspicious transaction procedures cover attempted and completed transactions and the standard for filing.','Policy covers attempted and completed transactions and says reports must be filed as soon as practicable.',NULL,'10','Reporting Obligations','STR','REP-04',false),
('policies_procedures','core_controls','reporting_obligations',77,'EFT and VC travel rule','PCMLTFR',true,77,'Requirement',NULL,'Confirm travel rule requirements are addressed for EFT and VC transfer contexts.','Required data elements / exception-handling / escalation are covered for EFT and VC; policy does not misstate STR as a travel-rule report.',NULL,'10','Reporting Obligations','Travel rule','REP-05',false),
('policies_procedures','core_controls','reporting_obligations',78,'STR sanctions evasion coverage','PCMLTFR',true,78,'Requirement',NULL,'Confirm STR procedures expressly include sanctions evasion-related suspicions.','Attempted and completed sanctions evasion suspicions route to STR logic.',NULL,'10','Reporting Obligations','Sanctions evasion','REP-06',false),
('policies_procedures','core_controls','reporting_obligations',79,'Listed person or entity property report','PCMLTFR',true,79,'Requirement',NULL,'Confirm the current listed person or entity property report process is described.','Current report name/process and immediate timing are stated; superseded terminology is updated or cross-walked.',NULL,'10','Reporting Obligations','Property reporting','REP-07',false),
('policies_procedures','core_controls','reporting_obligations',80,'Parallel reporting / law enforcement link','PCMLTFA / PCMLTFR',true,80,'Requirement',NULL,'Confirm the policy explains when more than one report/escalation may be required (e.g., LPEPR plus STR, or law-enforcement notification under other laws).','Parallel reporting/escalation logic is documented.',NULL,'10','Reporting Obligations','Property reporting','REP-08',false),
('policies_procedures','core_controls','reporting_obligations',81,'Submission method','FINTRAC Guidance',true,81,'Requirement',NULL,'Confirm the policy tells staff how reports are filed (portal/API/manual fallback where relevant).','Submission channels and fallback/manual paths are specified.',NULL,'10','Reporting Obligations','Submission mechanics','REP-09',false),
('policies_procedures','core_controls','reporting_obligations',82,'Public-private partnership / project name field','FINTRAC Guidance',true,82,'Best Practice',NULL,'If applicable to the organization, confirm the policy explains when the STR public-private partnership/project-name field is used (e.g., CP North-style initiative).','Optional field usage is controlled and approved; N/A if not used.',NULL,'10','Reporting Obligations','Optional field','REP-10',false);
