-- Policies & Procedures module — full working-paper rebuild
--
-- Replaces the legacy 120-question library with the firm's Excel working
-- paper (~100 controls across 14 sections) and switches scoring from a
-- uniform 2-point system to the FINTRAC harm-done taxonomy.
--
-- What this migration does:
-- 1. Adds `subsection` to `aml_program_question_templates`
--    (new Section → Subsection → Question hierarchy).
-- 2. Adds `finding_type` to `aml_pp_control_results` so each row can carry
--    a FINTRAC classification picked by the analyst.
-- 3. Adds `overall_finding_type` to `aml_pp_reviews` for the single overall
--    P&P verdict (keeps legacy `overall_design_rating` for backwards compat).
-- 4. Soft-deletes the existing core_controls templates for
--    `policies_procedures` (preserves any captured responses).
-- 5. Inserts the new control set using the firm's control IDs
--    (DCG-, ECR-, RR-, MSB-, KYC-, BR-, TPD-, BO-, PEP-, REP-, SAN-, RK-,
--    TRN-, LED-) with `analyst_guidance` = the analyst test and
--    `pass_criteria` = the pass criterion from the spreadsheet.
-- 6. Drops the obsolete dedicated "Agents, Correspondents & Special
--    Relationships" section — agent oversight survives via RK-07.

-- =========================================================================
-- 1. Schema additions
-- =========================================================================

ALTER TABLE public.aml_program_question_templates
  ADD COLUMN IF NOT EXISTS subsection text;

ALTER TABLE public.aml_pp_control_results
  ADD COLUMN IF NOT EXISTS finding_type text;

ALTER TABLE public.aml_pp_reviews
  ADD COLUMN IF NOT EXISTS overall_finding_type text,
  ADD COLUMN IF NOT EXISTS overall_finding_type_overridden boolean NOT NULL DEFAULT false;

-- =========================================================================
-- 2. Soft-delete legacy P&P core_controls templates
-- =========================================================================

UPDATE public.aml_program_question_templates
SET is_active = false
WHERE submodule = 'policies_procedures'
  AND control_area = 'core_controls';

-- =========================================================================
-- 3. Insert the firm's working paper
-- =========================================================================
-- Each row carries:
--   section_code  — numeric section label ('1' .. '14')
--   section_name  — full section title
--   subsection    — subsection name from the spreadsheet
--   question_code — firm's control ID (DCG-01, etc.)
--   question_text — "Control Area" column from the spreadsheet
--   analyst_guidance — "Analyst test / what to check" column
--   pass_criteria    — "Pass criteria" column
--   evidence_required = true for every row (P&P review always needs the doc)
--   max_points = NULL (we no longer score; finding_type is per-response)
--   regulatory_reference — best-fit primary reference per section

-- ---------------- Section 1: Document Control & Governance ----------------

-- ---------------- Section 2: Effective Compliance Regime ----------------

-- ---------------- Section 3: Roles & Responsibilities ----------------

-- ---------------- Section 4: MSB Registration & FINTRAC Notifications ----------------

-- ---------------- Section 5: Client Identification & KYC ----------------

-- ---------------- Section 6: Business Relationship & Ongoing Monitoring ----------------

-- ---------------- Section 7: Third Party Determination ----------------

-- ---------------- Section 8: Beneficial Ownership & Discrepancy Reporting ----------------

-- ---------------- Section 9: PEP / HIO ----------------

-- ---------------- Section 10: Reporting Obligations ----------------

-- ---------------- Section 11: Sanctions & Ministerial Directives ----------------

-- ---------------- Section 12: Recordkeeping ----------------

-- ---------------- Section 13: Training Program ----------------

-- ---------------- Section 14: Law Enforcement, Disclosures & Self-Disclosure ----------------

NOTIFY pgrst, 'reload schema';
